package com.example.chunker.safeloop.distributed;

import com.example.chunker.refactor.ChatService;
import com.example.chunker.refactor.RefactorAgent;
import com.example.chunker.refactor.RefactorTools;
import com.example.chunker.retrieval.RetrievalResult;
import com.example.chunker.safeloop.SafeLoopResult;
import com.example.chunker.safeloop.SafeLoopTools;
import com.example.chunker.safeloop.SafetyVerdict;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;

/**
 * Distributed self-improving refactoring loop with separate LLM machines.
 *
 * <p>This is the multi-machine evolution of {@link com.example.chunker.safeloop.SafeRefactorLoop}.
 * The Generator and Critic run on physically separate machines, communicating
 * via a structured JSON protocol defined in {@link DistributedSafetyVerdict}.
 *
 * <h3>Architecture:</h3>
 * <pre>
 *   ┌──────────────────────────────────────────────────────────────┐
 *   │                    ORCHESTRATOR (this class)                  │
 *   │                                                              │
 *   │  ┌─────────────────────┐      ┌─────────────────────┐       │
 *   │  │  REFACTOR_MACHINE   │      │  S_ANALYZE_MACHINE  │       │
 *   │  │  http://REFACTORM   │      │  http://SANALYZEM   │       │
 *   │  │  :1234              │      │  :1234              │       │
 *   │  │                     │      │                     │       │
 *   │  │   Generator LLM   │      │   Critic LLM      │       │
 *   │  │  "Senior Java       │      │  "Strict static     │       │
 *   │  │   engineer"         │      │   analyzer"         │       │
 *   │  │  temp=0.3           │      │  temp=0.1           │       │
 *   │  │  Tool-calling: YES  │      │  Tool-calling: NO   │       │
 *   │  └─────────┬───────────┘      └──────────┬──────────┘       │
 *   │            │                              │                  │
 *   │            │    JSON Protocol             │                  │
 *   │            │  ◄──────────────────────────►│                  │
 *   │            │                              │                  │
 *   │  ┌─────────┴──────────────────────────────┴──────────┐      │
 *   │  │              Graph Retrieval Layer                  │      │
 *   │  │       Neo4j + Embeddings (runs locally)            │      │
 *   │  └───────────────────────────────────────────────────┘      │
 *   └──────────────────────────────────────────────────────────────┘
 * </pre>
 *
 * <h3>Loop flow:</h3>
 * <pre>
 *   1. Initial retrieval + graph coverage enforcement (local)
 *   2. Generator proposes refactoring (REFACTOR_MACHINE, with tool calling)
 *   3. Orchestrator packages proposal as JSON → sends to Analyzer
 *   4. Analyzer evaluates → returns structured JSON verdict:
 *        { "safe": false, "confidence": 0.65, "issues": [...], "missing_context": [...] }
 *   5. If UNSAFE:
 *        a. Orchestrator fetches missing_context from graph
 *        b. Orchestrator packages issues + new context as JSON → sends to Generator
 *        c. Generator refines → goto 3
 *   6. If SAFE → return result
 *   7. If CONVERGED/STAGNANT → return best-effort
 * </pre>
 *
 * <h3>JSON wire protocol between machines:</h3>
 * <p>See {@link DistributedSafetyVerdict} for the complete protocol specification.
 */
public class DistributedSafeRefactorLoop {

    // ═══════════════════════════════════════════════════════════════
    //  Generator system prompt — Senior Java Engineer role
    // ═══════════════════════════════════════════════════════════════

    private static final String GENERATOR_SYSTEM_PROMPT = """
        You are a senior Java engineer.

        Goal:
        Refactor code safely.

        Rules:
        - Do not assume missing dependencies
        - If unsure, state assumptions
        - Keep changes minimal and correct
        - ALWAYS gather context before suggesting changes. Never guess at code you haven't seen.
        - If you lack context about a method or class, call the appropriate retrieval tool.
        - Always check callers of a method before changing its signature (impact analysis).
        - Always check callees before refactoring a method body (dependency analysis).

        You have access to these tools:
        - retrieveCode(query): Search the codebase using natural language.
        - retrieveCodeById(methodId, depth): Fetch a specific method and its graph neighbourhood.
        - getMethodCallers(methodId): Find all callers of a method (impact analysis).
        - getMethodCallees(methodId): Find all callees of a method (dependency analysis).

        Response format (after gathering all context):
        Produce your response as structured JSON:
        {
          "refactored_code": "... the complete refactored code ...",
          "changes": [
            { "file": "ClassName.java", "method": "methodName", "description": "what changed" }
          ],
          "explanation": "Brief explanation of what changed and why",
          "assumptions": ["assumption 1", "assumption 2"],
          "breaking_changes": ["breaking change 1", "breaking change 2"]
        }

        If there are no breaking changes, use an empty array: "breaking_changes": []
        If there are no assumptions, use an empty array: "assumptions": []
        """;

    // ═══════════════════════════════════════════════════════════════
    //  Critic system prompt — Strict Static Analyzer role
    // ═══════════════════════════════════════════════════════════════

    private static final String ANALYZER_SYSTEM_PROMPT = """
        You are a strict static analyzer.

        Your job:
        - Find bugs
        - Find breaking changes
        - Reject unsafe refactoring

        You MUST be conservative.
        If uncertain → request more context.

        You must evaluate the proposed refactoring and return your analysis as STRICT JSON.

        Your output MUST be this exact JSON structure and nothing else:
        {
          "safe": false,
          "confidence": 0.65,
          "issues": [
            {
              "description": "Description of the issue found",
              "severity": "HIGH",
              "mitigation": "How to fix this issue"
            }
          ],
          "missing_context": [
            "ClassName#methodName that you need to see"
          ],
          "summary": "Brief overall assessment"
        }

        Rules:
        - "safe" must be true ONLY if you are certain the refactoring introduces no bugs or breaking changes
        - "confidence" must be between 0.0 and 1.0, reflecting your actual certainty
        - "severity" must be one of: "HIGH", "MEDIUM", "LOW"
        - HIGH = compilation error, broken callers, data loss, security issue
        - MEDIUM = potential runtime issue, performance concern, incomplete handling
        - LOW = style issue, minor improvement opportunity
        - If you don't have enough context to judge safety, set confidence LOW and list what you need in "missing_context"
        - Each entry in "missing_context" should be "ClassName#methodName" format
        - If there are no issues, use an empty array: "issues": []
        - If you don't need more context, use an empty array: "missing_context": []
        - Return ONLY the JSON. No markdown, no explanatory text before or after.
        """;

    // ═══════════════════════════════════════════════════════════════
    // Fields
    // ═══════════════════════════════════════════════════════════════

    /** The refactoring agent (runs on REFACTOR_MACHINE). Uses tool calling. */
    private final RefactorAgent generatorAgent;

    /** The analyzer chat service (runs on S_ANALYZE_MACHINE). No tool calling. */
    private final ChatService analyzerChat;

    /** Programmatic graph tools (runs locally on orchestrator). */
    private final SafeLoopTools loopTools;

    /** Agent tools for tool-call count tracking. */
    private final RefactorTools agentTools;

    /** Configuration. */
    private final DistributedSafeLoopConfig config;

    /** Callback for streaming progress updates. */
    private Consumer<String> progressCallback;

    public DistributedSafeRefactorLoop(RefactorAgent generatorAgent,
                                        ChatService analyzerChat,
                                        SafeLoopTools loopTools,
                                        RefactorTools agentTools,
                                        DistributedSafeLoopConfig config) {
        this.generatorAgent = generatorAgent;
        this.analyzerChat = analyzerChat;
        this.loopTools = loopTools;
        this.agentTools = agentTools;
        this.config = config;
        this.progressCallback = System.out::print;
    }

    public void setProgressCallback(Consumer<String> callback) {
        this.progressCallback = callback;
    }

    // ═══════════════════════════════════════════════════════════════
    // Main entry point
    // ═══════════════════════════════════════════════════════════════

    /**
     * Run the distributed safe refactoring loop.
     *
     * <p>The loop coordinates between two separate LLM machines:
     * <ul>
     *   <li>REFACTOR_MACHINE (Generator) — proposes code changes with tool calling</li>
     *   <li>S_ANALYZE_MACHINE (Critic) — evaluates safety via structured JSON</li>
     * </ul>
     *
     * @param userQuery the natural-language refactoring request
     * @return the complete result including safety verdict and diagnostics
     */
    public SafeLoopResult run(String userQuery) {
        printBanner();
        System.out.println("Query: " + userQuery);
        System.out.println("Config: " + config);
        System.out.println();

        List<SafetyVerdict> verdictHistory = new ArrayList<>();
        List<DistributedSafetyVerdict> distributedVerdicts = new ArrayList<>();
        String lastAgentResponse = "";
        SafeLoopResult.TerminalReason terminalReason = SafeLoopResult.TerminalReason.MAX_ITERATIONS;

        try {
            // ══════════════════════════════════════════════════════
            // Phase 1: PLANNING — Initial retrieval + target identification
            // ══════════════════════════════════════════════════════
            System.out.println("━━━ Phase 1: Planning & Initial Retrieval ━━━━━━━━━━━");

            List<RetrievalResult> initialResults = loopTools.initialRetrieve(userQuery);
            System.out.println("  Retrieved " + initialResults.size() + " initial chunks");

            String anchorId = loopTools.findAnchorId(initialResults);
            System.out.println("  Anchor method: " + (anchorId != null ? anchorId : "(none)"));
            System.out.println();

            // ══════════════════════════════════════════════════════
            // Phase 2: GRAPH PRE-FETCH — Ensure minimum coverage
            // ══════════════════════════════════════════════════════
            System.out.println("━━━ Phase 2: Graph Coverage Enforcement ━━━━━━━━━━━━━");

            String preContext = "";
            if (anchorId != null) {
                preContext = loopTools.ensureGraphCoverage(anchorId);
                if (!preContext.isEmpty()) {
                    System.out.println("  Pre-fetched " + loopTools.getLastExpansionChunks().size()
                        + " additional methods for coverage");
                } else {
                    System.out.println("  Graph coverage already satisfied");
                }
            } else {
                System.out.println("  ⚠ No anchor method found, skipping coverage enforcement");
            }
            System.out.println("  Total nodes in context: " + loopTools.getTotalNodesRetrieved());
            System.out.println();

            // ══════════════════════════════════════════════════════
            // Phase 3→5: GENERATE → EVALUATE → DECIDE (iterative)
            // ══════════════════════════════════════════════════════

            for (int iteration = 0; iteration < config.getMaxIterations(); iteration++) {
                String iterLabel = "Iteration " + (iteration + 1) + "/" + config.getMaxIterations();

                // ── Phase 3: GENERATE (REFACTOR_MACHINE) ──
                System.out.println("━━━ " + iterLabel + ": Phase 3 —  Generator (REFACTOR_MACHINE) ━━━");

                agentTools.resetToolCallCount();

                if (iteration == 0) {
                    // First iteration: send the original query + pre-fetched context
                    String enhancedQuery = userQuery;
                    if (!preContext.isEmpty()) {
                        enhancedQuery = userQuery + "\n\nHere is additional context from the code graph:\n\n"
                            + preContext;
                    }
                    lastAgentResponse = generatorAgent.getAssistant().chat(enhancedQuery);
                } else {
                    // Subsequent iterations: send structured JSON refinement request
                    DistributedSafetyVerdict lastVerdict = distributedVerdicts.get(distributedVerdicts.size() - 1);

                    // Fetch any missing context the analyzer requested
                    String newContext = "";
                    if (lastVerdict.needsMoreContext()) {
                        newContext = loopTools.expandForAnalyzer(lastVerdict.getMissingContext());
                    }

                    String refinementJson = DistributedSafetyVerdict.buildRefinementRequest(
                        userQuery, lastVerdict, iteration + 1, newContext);

                    System.out.println("  ┌─ Refinement request (JSON) ─────────────────────");
                    System.out.println("  │ " + truncateForLog(refinementJson, 400).replace("\n", "\n  │ "));
                    System.out.println("  └─────────────────────────────────────────────────");

                    // The agent receives the structured feedback and refines
                    lastAgentResponse = generatorAgent.getAssistant().chat(
                        "The safety analyzer found issues with your refactoring. "
                        + "Here is the structured feedback:\n\n" + refinementJson
                        + "\n\nPlease address ALL issues and produce a refined refactoring."
                    );
                }

                System.out.println("  Generator responded (" + agentTools.getToolCallCount() + " tool calls)");
                System.out.println();

                // ── Phase 4: EVALUATE (S_ANALYZE_MACHINE) ──
                System.out.println("━━━ " + iterLabel + ": Phase 4 —  Critic (S_ANALYZE_MACHINE) ━━━━━");

                // Build the structured evaluation request (JSON protocol)
                String evaluationJson = DistributedSafetyVerdict.buildEvaluationRequest(
                    userQuery,
                    lastAgentResponse,
                    iteration + 1,
                    loopTools.getTotalNodesRetrieved(),
                    loopTools.getExpansionCount()
                );

                System.out.println("  ┌─ Evaluation request (JSON) ──────────────────────");
                System.out.println("  │ " + truncateForLog(evaluationJson, 400).replace("\n", "\n  │ "));
                System.out.println("  └──────────────────────────────────────────────────");

                // Send to analyzer — it must return the structured JSON verdict
                String analyzerPrompt = "Evaluate this refactoring proposal. "
                    + "Return your analysis as the required JSON structure.\n\n"
                    + evaluationJson;

                System.out.println("  ┌─  Analyzer Response ──────────────────────────");
                String analyzerResponse = analyzerChat.chat(ANALYZER_SYSTEM_PROMPT, analyzerPrompt);
                System.out.println("  │ " + truncateForLog(analyzerResponse, 500).replace("\n", "\n  │ "));
                System.out.println("  └──────────────────────────────────────────────────");

                // Parse the JSON verdict
                DistributedSafetyVerdict verdict = DistributedSafetyVerdict.parse(analyzerResponse);
                distributedVerdicts.add(verdict);

                // Also create a SafetyVerdict for backwards compatibility with SafeLoopResult
                SafetyVerdict compatVerdict = convertToSafetyVerdict(verdict);
                verdictHistory.add(compatVerdict);

                System.out.println();
                System.out.println("  → " + verdict);

                if (!verdict.isParsedFromJson()) {
                    System.out.println("  ⚠ WARNING: Analyzer did not return valid JSON. Using fallback parsing.");
                }

                // ── Phase 5: DECIDE ──
                System.out.println("━━━ " + iterLabel + ": Phase 5 — Decision ━━━━━━━━━━━━━");

                // Check: SAFE?
                if (verdict.isSafe(config.getSafetyThreshold())) {
                    System.out.println("  → ✓ SAFE — confidence " + String.format("%.2f", verdict.getConfidence())
                        + " ≥ threshold " + String.format("%.2f", config.getSafetyThreshold()));
                    System.out.println();
                    terminalReason = SafeLoopResult.TerminalReason.SAFE;
                    break;
                }

                // Check: Stagnation?
                if (config.isStopOnStagnation() && distributedVerdicts.size() >= 2) {
                    DistributedSafetyVerdict prev = distributedVerdicts.get(distributedVerdicts.size() - 2);
                    if (verdict.hasSameIssues(prev)) {
                        System.out.println("  → ✗ STAGNANT — same issues as previous iteration, stopping");
                        System.out.println();
                        terminalReason = SafeLoopResult.TerminalReason.STAGNANT;
                        break;
                    }
                }

                // Check: More context needed?
                if (verdict.needsMoreContext()) {
                    System.out.println("  → Analyzer needs more context: " + verdict.getMissingContext());
                    String newContext = loopTools.expandForAnalyzer(verdict.getMissingContext());

                    if (newContext.isEmpty() || !loopTools.hasNewNodes()) {
                        if (config.isStopOnNoNewNodes()) {
                            System.out.println("  → ✗ CONVERGED — no new graph nodes available, stopping");
                            System.out.println();
                            terminalReason = SafeLoopResult.TerminalReason.CONVERGED;
                            break;
                        }
                        System.out.println("  → ⚠ No new nodes, but continuing (stopOnNoNewNodes=false)");
                    } else {
                        System.out.println("  → Expanded graph: +" + loopTools.getLastExpansionChunks().size()
                            + " new methods (total: " + loopTools.getTotalNodesRetrieved() + ")");

                        // Inject new context into agent memory so Generator has it next round
                        generatorAgent.getAssistant().chat(
                            "Here is additional context retrieved from the code graph. "
                            + "Use this in your next refinement:\n\n" + newContext
                        );
                    }
                } else {
                    System.out.println("  → ✗ UNSAFE (confidence " + String.format("%.2f", verdict.getConfidence())
                        + ") — issues found but analyzer doesn't need more context");
                }

                System.out.println("  → Looping for refinement...");
                System.out.println();
            }

            // ── Build final result ──
            SafetyVerdict finalCompat = verdictHistory.isEmpty() ? null : verdictHistory.get(verdictHistory.size() - 1);
            DistributedSafetyVerdict finalDistributed = distributedVerdicts.isEmpty()
                ? null : distributedVerdicts.get(distributedVerdicts.size() - 1);
            boolean isSafe = finalDistributed != null && finalDistributed.isSafe(config.getSafetyThreshold());

            return new SafeLoopResult(
                userQuery,
                lastAgentResponse,
                extractExplanation(lastAgentResponse),
                isSafe,
                finalDistributed != null ? finalDistributed.getConfidence() : 0.0,
                terminalReason,
                verdictHistory.size(),
                verdictHistory,
                agentTools.getToolCallCount(),
                loopTools.getTotalNodesRetrieved(),
                finalCompat != null ? finalCompat.getRisks() : List.of(),
                lastAgentResponse
            );

        } catch (Exception e) {
            System.err.println("  ✗ ERROR: " + e.getMessage());
            e.printStackTrace();

            return new SafeLoopResult(
                userQuery, "", "Error: " + e.getMessage(),
                false, 0.0,
                SafeLoopResult.TerminalReason.ERROR,
                verdictHistory.size(), verdictHistory,
                agentTools.getToolCallCount(), loopTools.getTotalNodesRetrieved(),
                List.of(), lastAgentResponse
            );
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // Compatibility converter
    // ═══════════════════════════════════════════════════════════════

    /**
     * Convert a {@link DistributedSafetyVerdict} to the legacy
     * {@link SafetyVerdict} format for backwards compatibility
     * with {@link SafeLoopResult}.
     */
    private SafetyVerdict convertToSafetyVerdict(DistributedSafetyVerdict dv) {
        // Build a synthetic analyzer response in the old format
        StringBuilder sb = new StringBuilder();
        sb.append("CONFIDENCE: ").append(String.format("%.2f", dv.getConfidence())).append("\n");
        sb.append("VERDICT: ").append(dv.isSafe() ? "SAFE" : "UNSAFE").append("\n\n");

        if (!dv.getIssues().isEmpty()) {
            sb.append("RISKS:\n");
            for (DistributedSafetyVerdict.Issue issue : dv.getIssues()) {
                sb.append("- RISK: ").append(issue.getDescription())
                    .append(" | SEVERITY: ").append(issue.getSeverity())
                    .append(" | MITIGATION: ").append(issue.getMitigation().isEmpty()
                        ? "N/A" : issue.getMitigation())
                    .append("\n");
            }
        } else {
            sb.append("RISKS: none\n");
        }

        sb.append("\n");
        if (!dv.getMissingContext().isEmpty()) {
            sb.append("NEEDS:\n");
            for (String ctx : dv.getMissingContext()) {
                sb.append("- ").append(ctx).append("\n");
            }
        } else {
            sb.append("NEEDS: none\n");
        }

        sb.append("\nFEEDBACK:\n").append(dv.getSummary());

        return SafetyVerdict.parse(sb.toString());
    }

    // ═══════════════════════════════════════════════════════════════
    // Helpers
    // ═══════════════════════════════════════════════════════════════

    private void printBanner() {
        System.out.println("╔═══════════════════════════════════════════════════════════╗");
        System.out.println("║  Distributed Safe Refactoring Loop                        ║");
        System.out.println("║   Generator (REFACTOR_MACHINE) ↔  Critic (S_ANALYZE) ║");
        System.out.println("║  JSON protocol between machines                           ║");
        System.out.println("╚═══════════════════════════════════════════════════════════╝");
        System.out.println();
    }

    /**
     * Extract a rough explanation from the agent's response.
     */
    private static String extractExplanation(String response) {
        if (response == null || response.isBlank()) return "";

        // Try JSON-based extraction first
        int explIdx = response.toLowerCase().indexOf("\"explanation\"");
        if (explIdx >= 0) {
            // Simple extraction: find the value after "explanation": "..."
            int colonIdx = response.indexOf(':', explIdx);
            if (colonIdx >= 0) {
                int startQuote = response.indexOf('"', colonIdx + 1);
                if (startQuote >= 0) {
                    int endQuote = response.indexOf('"', startQuote + 1);
                    // Handle escaped quotes
                    while (endQuote > 0 && response.charAt(endQuote - 1) == '\\') {
                        endQuote = response.indexOf('"', endQuote + 1);
                    }
                    if (endQuote > startQuote) {
                        return response.substring(startQuote + 1, endQuote);
                    }
                }
            }
        }

        // Fall back to text-based extraction
        explIdx = response.toLowerCase().indexOf("explanation:");
        if (explIdx >= 0) {
            String after = response.substring(explIdx + "explanation:".length()).trim();
            int end = findSectionEnd(after);
            return end >= 0 ? after.substring(0, end).trim() : after.trim();
        }

        return "";
    }

    private static int findSectionEnd(String text) {
        String[] headers = {"CHANGES:", "BREAKING", "MISSING:", "```", "\"changes\"", "\"breaking"};
        int earliest = -1;
        for (String header : headers) {
            int idx = text.toLowerCase().indexOf(header.toLowerCase());
            if (idx > 0 && (earliest < 0 || idx < earliest)) {
                earliest = idx;
            }
        }
        return earliest;
    }

    private static String truncateForLog(String text, int maxLen) {
        if (text.length() <= maxLen) return text;
        return text.substring(0, maxLen) + "\n... (" + text.length() + " chars total)";
    }
}

package com.example.chunker.safeloop.distributed;

import com.example.chunker.safeloop.SafeLoopResult;
import com.example.chunker.safeloop.SafetyVerdict;

import java.util.ArrayList;
import java.util.List;
import java.util.function.Consumer;

/**
 * Distributed planner-driven safe refactoring loop.
 *
 * <p>This is the evolution from the manual orchestrator loop to a planner-driven
 * agentic architecture. The Planner–Analyzer on S_ANALYZE_MACHINE has full
 * authority — it decides what to retrieve, when to invoke the Generator, and
 * when to stop.
 *
 * <h3>Architecture:</h3>
 * <pre>
 *   ┌──────────────────────────────────────────────────────────────┐
 *   │              PLANNER-DRIVEN REFACTORING LOOP                 │
 *   │                                                              │
 *   │  ┌─────────────────────┐      ┌─────────────────────┐       │
 *   │  │  REFACTOR_MACHINE   │      │  S_ANALYZE_MACHINE  │       │
 *   │  │  http://REFACTORM   │      │  http://SANALYZEM   │       │
 *   │  │  :1234              │      │  :1234              │       │
 *   │  │                     │      │                     │       │
 *   │  │   Generator LLM   │      │   Planner–Analyzer│       │
 *   │  │  "Senior Java       │      │  "Senior architect  │       │
 *   │  │   engineer"         │      │   + static analyzer"│       │
 *   │  │  temp=0.3           │      │  temp=0.1           │       │
 *   │  │  Tool-calling: NO   │      │  Tool-calling: YES  │       │
 *   │  │  No decision auth   │      │  Full authority     │       │
 *   │  └─────────┬───────────┘      └──────────┬──────────┘       │
 *   │            │                              │                  │
 *   │            │  refactorCode() via          │                  │
 *   │            │  planner tool call           │                  │
 *   │            │ ◄────────────────────────────┤                  │
 *   │            │                              │                  │
 *   │            │  retrieveCode()              │                  │
 *   │            │  getMethodCallers()           │                  │
 *   │            │  getMethodCallees()           │                  │
 *   │            │  ────────────────────────────►│                  │
 *   │            │                              │                  │
 *   │  ┌─────────┴──────────────────────────────┴──────────┐      │
 *   │  │              Graph Retrieval Layer                  │      │
 *   │  │       Neo4j + Embeddings (runs locally)            │      │
 *   │  └───────────────────────────────────────────────────┘      │
 *   └──────────────────────────────────────────────────────────────┘
 * </pre>
 *
 * <h3>Planner-driven flow:</h3>
 * <pre>
 *   1. User submits refactoring request
 *   2. Planner autonomously:
 *      a. Plans what context is needed
 *      b. Calls retrieval tools (retrieveCode, getMethodCallers, getMethodCallees)
 *      c. Validates sufficient context (callees, callers, shared state)
 *      d. Delegates to Generator via refactorCode() tool
 *      e. Critically validates the Generator's response
 *      f. If unsafe → retrieves more context → asks Generator to retry
 *      g. Repeats until confidence &gt; 0.9 or max steps reached
 *   3. Planner returns structured JSON verdict
 * </pre>
 *
 * <h3>Guardrails:</h3>
 * <ul>
 *   <li>Max planner steps (tool calls) — default 8</li>
 *   <li>Max chunks per retrieval — default 10</li>
 *   <li>Max retrieval depth — default 2 hops</li>
 *   <li>Safety threshold — confidence must be &gt; 0.9</li>
 *   <li>Planner must retrieve callers + callees before refactoring (enforced in prompt)</li>
 * </ul>
 */
public class DistributedSafeRefactorLoop {

    // ═══════════════════════════════════════════════════════════════
    // Fields
    // ═══════════════════════════════════════════════════════════════

    /** The planner–analyzer agent (runs on S_ANALYZE_MACHINE). Controls everything. */
    private final PlannerAgent plannerAgent;

    /** Configuration. */
    private final DistributedSafeLoopConfig config;

    /** Callback for streaming progress updates. */
    private Consumer<String> progressCallback;

    public DistributedSafeRefactorLoop(PlannerAgent plannerAgent,
                                        DistributedSafeLoopConfig config) {
        this.plannerAgent = plannerAgent;
        this.config = config;
        this.progressCallback = System.out::print;
    }

    public void setProgressCallback(Consumer<String> callback) {
        this.progressCallback = callback;
    }

    // ═══════════════════════════════════════════════════════════════
    // Main entry point
    // ═══════════════════════════════════════════════════════════════

    /**
     * Run the planner-driven safe refactoring loop.
     *
     * <p>Instead of a manual orchestrator loop, the Planner–Analyzer agent
     * on S_ANALYZE_MACHINE autonomously drives the entire process using
     * LangChain4j tool calling:
     * <ul>
     *   <li>retrieval tools — to gather code context from the graph</li>
     *   <li>refactorCode() — to delegate code generation to the Generator</li>
     *   <li>validation — built into the planner's reasoning loop</li>
     * </ul>
     *
     * @param userQuery the natural-language refactoring request
     * @return the complete result including safety verdict and diagnostics
     */
    public SafeLoopResult run(String userQuery) {
        printBanner();
        System.out.println("Query: " + userQuery);
        System.out.println("Config: " + config);
        System.out.println();

        List<SafetyVerdict> verdictHistory = new ArrayList<>();
        String plannerResponse = "";
        SafeLoopResult.TerminalReason terminalReason = SafeLoopResult.TerminalReason.MAX_ITERATIONS;

        try {
            // ══════════════════════════════════════════════════════
            // Single call: Planner drives everything autonomously
            // ══════════════════════════════════════════════════════
            System.out.println("━━━ Planner–Analyzer Autonomous Loop ━━━━━━━━━━━━━━━━━━");
            System.out.println("  The planner will autonomously:");
            System.out.println("    1. Plan refactoring steps");
            System.out.println("    2. Retrieve all necessary context from the code graph");
            System.out.println("    3. Delegate refactoring to Generator (REFACTOR_MACHINE)");
            System.out.println("    4. Validate results and iterate until safe");
            System.out.println();

            plannerResponse = plannerAgent.plan(userQuery);

            System.out.println("━━━ Planner Response ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
            System.out.println("  " + truncateForLog(plannerResponse, 600).replace("\n", "\n  "));
            System.out.println();

            // ══════════════════════════════════════════════════════
            // Parse the planner's final JSON verdict
            // ══════════════════════════════════════════════════════
            DistributedSafetyVerdict verdict = DistributedSafetyVerdict.parse(plannerResponse);

            // Also extract refactored code if the planner included it
            String refactoredCode = extractRefactoredCode(plannerResponse);

            // Create a SafetyVerdict for compatibility
            SafetyVerdict compatVerdict = convertToSafetyVerdict(verdict);
            verdictHistory.add(compatVerdict);

            System.out.println("━━━ Final Verdict ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
            System.out.println("  " + verdict);

            if (!verdict.isParsedFromJson()) {
                System.out.println("  ⚠ WARNING: Planner did not return valid JSON. Using fallback parsing.");
            }

            // Determine terminal reason
            PlannerTools tools = plannerAgent.getTools();
            if (verdict.isSafe(config.getSafetyThreshold())) {
                terminalReason = SafeLoopResult.TerminalReason.SAFE;
                System.out.println("  → ✓ SAFE — confidence " + String.format("%.2f", verdict.getConfidence())
                    + " ≥ threshold " + String.format("%.2f", config.getSafetyThreshold()));
            } else if (tools.getToolCallCount() == 0) {
                terminalReason = SafeLoopResult.TerminalReason.ERROR;
                System.out.println("  → ✗ ERROR — planner made no tool calls");
            } else {
                // Planner finished but wasn't confident enough
                if (verdict.getConfidence() > 0) {
                    terminalReason = SafeLoopResult.TerminalReason.MAX_ITERATIONS;
                    System.out.println("  → ✗ UNSAFE — planner finished with confidence "
                        + String.format("%.2f", verdict.getConfidence())
                        + " < threshold " + String.format("%.2f", config.getSafetyThreshold()));
                } else {
                    terminalReason = SafeLoopResult.TerminalReason.CONVERGED;
                    System.out.println("  → ✗ CONVERGED — planner could not improve further");
                }
            }

            System.out.println();
            System.out.println("   Planner stats:");
            System.out.println("     Tool calls: " + tools.getToolCallCount());
            System.out.println("     Refactor delegations: " + tools.getRefactorCallCount());
            System.out.println("     Graph nodes retrieved: " + tools.getTotalNodesRetrieved());
            System.out.println();

            boolean isSafe = verdict.isSafe(config.getSafetyThreshold());

            // Use the generator's last result if available, otherwise the planner response
            String finalCode = refactoredCode.isEmpty()
                ? tools.getLastRefactoringResult()
                : refactoredCode;

            return new SafeLoopResult(
                userQuery,
                finalCode,
                extractExplanation(plannerResponse),
                isSafe,
                verdict.getConfidence(),
                terminalReason,
                verdictHistory.size(),
                verdictHistory,
                tools.getToolCallCount(),
                tools.getTotalNodesRetrieved(),
                compatVerdict != null ? compatVerdict.getRisks() : List.of(),
                plannerResponse
            );

        } catch (Exception e) {
            System.err.println("  ✗ ERROR: " + e.getMessage());
            e.printStackTrace();

            return new SafeLoopResult(
                userQuery, "", "Error: " + e.getMessage(),
                false, 0.0,
                SafeLoopResult.TerminalReason.ERROR,
                verdictHistory.size(), verdictHistory,
                plannerAgent.getTools().getToolCallCount(),
                plannerAgent.getTools().getTotalNodesRetrieved(),
                List.of(), plannerResponse
            );
        }
    }

    // ═══════════════════════════════════════════════════════════════
    // Compatibility converter
    // ═══════════════════════════════════════════════════════════════

    /**
     * Convert a {@link DistributedSafetyVerdict} to the legacy
     * {@link SafetyVerdict} format for backwards compatibility.
     */
    private SafetyVerdict convertToSafetyVerdict(DistributedSafetyVerdict dv) {
        StringBuilder sb = new StringBuilder();
        sb.append("CONFIDENCE: ").append(String.format("%.2f", dv.getConfidence())).append("\n");
        sb.append("VERDICT: ").append(dv.isSafe() ? "SAFE" : "UNSAFE").append("\n\n");

        if (!dv.getIssues().isEmpty()) {
            sb.append("RISKS:\n");
            for (DistributedSafetyVerdict.Issue issue : dv.getIssues()) {
                sb.append("- RISK: ").append(issue.getDescription())
                    .append(" | SEVERITY: ").append(issue.getSeverity())
                    .append(" | MITIGATION: ").append(issue.getMitigation().isEmpty()
                        ? "N/A" : issue.getMitigation())
                    .append("\n");
            }
        } else {
            sb.append("RISKS: none\n");
        }

        sb.append("\n");
        if (!dv.getMissingContext().isEmpty()) {
            sb.append("NEEDS:\n");
            for (String ctx : dv.getMissingContext()) {
                sb.append("- ").append(ctx).append("\n");
            }
        } else {
            sb.append("NEEDS: none\n");
        }

        sb.append("\nFEEDBACK:\n").append(dv.getSummary());

        return SafetyVerdict.parse(sb.toString());
    }

    // ═══════════════════════════════════════════════════════════════
    // Helpers
    // ═══════════════════════════════════════════════════════════════

    private void printBanner() {
        System.out.println("╔═══════════════════════════════════════════════════════════╗");
        System.out.println("║  Planner-Driven Distributed Refactoring Loop              ║");
        System.out.println("║   Generator (REFACTOR_MACHINE) — writes code            ║");
        System.out.println("║   Planner–Analyzer (S_ANALYZE) — controls everything    ║");
        System.out.println("║  Planner has tools: retrieve, refactor, validate           ║");
        System.out.println("╚═══════════════════════════════════════════════════════════╝");
        System.out.println();
    }

    /**
     * Extract refactored code from the planner's final JSON response.
     */
    private static String extractRefactoredCode(String response) {
        if (response == null || response.isBlank()) return "";

        // Try JSON-based extraction: "refactored_code": "..."
        int idx = response.toLowerCase().indexOf("\"refactored_code\"");
        if (idx >= 0) {
            int colonIdx = response.indexOf(':', idx);
            if (colonIdx >= 0) {
                int startQuote = response.indexOf('"', colonIdx + 1);
                if (startQuote >= 0) {
                    int endQuote = findClosingQuote(response, startQuote + 1);
                    if (endQuote > startQuote) {
                        return response.substring(startQuote + 1, endQuote)
                            .replace("\\n", "\n")
                            .replace("\\\"", "\"")
                            .replace("\\t", "\t");
                    }
                }
            }
        }

        return "";
    }

    /**
     * Find the closing quote, handling escaped quotes.
     */
    private static int findClosingQuote(String text, int start) {
        for (int i = start; i < text.length(); i++) {
            if (text.charAt(i) == '"' && text.charAt(i - 1) != '\\') {
                return i;
            }
        }
        return -1;
    }

    /**
     * Extract a rough explanation from the planner's response.
     */
    private static String extractExplanation(String response) {
        if (response == null || response.isBlank()) return "";

        // Try JSON-based extraction first
        int explIdx = response.toLowerCase().indexOf("\"explanation\"");
        if (explIdx >= 0) {
            int colonIdx = response.indexOf(':', explIdx);
            if (colonIdx >= 0) {
                int startQuote = response.indexOf('"', colonIdx + 1);
                if (startQuote >= 0) {
                    int endQuote = findClosingQuote(response, startQuote + 1);
                    if (endQuote > startQuote) {
                        return response.substring(startQuote + 1, endQuote);
                    }
                }
            }
        }

        // Try "summary" field
        int sumIdx = response.toLowerCase().indexOf("\"summary\"");
        if (sumIdx >= 0) {
            int colonIdx = response.indexOf(':', sumIdx);
            if (colonIdx >= 0) {
                int startQuote = response.indexOf('"', colonIdx + 1);
                if (startQuote >= 0) {
                    int endQuote = findClosingQuote(response, startQuote + 1);
                    if (endQuote > startQuote) {
                        return response.substring(startQuote + 1, endQuote);
                    }
                }
            }
        }

        return "";
    }

    private static String truncateForLog(String text, int maxLen) {
        if (text.length() <= maxLen) return text;
        return text.substring(0, maxLen) + "\n... (" + text.length() + " chars total)";
    }
}
